import { NextResponse } from "next/server";
import { getProperties, unpublishProperty } from "@/lib/firestore";

// --- Types ---
interface Property {
  id: string;
  referenceNumber: string;
  price: number;
  leadsCount?: number;
  isPublished?: boolean;
}

interface LeadData {
  total_leads: number;
}

interface EvaluationResult {
  shouldUnpublish: boolean;
  reason: string;
  isHighValue: boolean;
  leadsFound: number;
}

// --- Helper Functions ---

/**
 * Fetch real-time lead data from Property Finder CRM API
 */
async function fetchCRMLeads(referenceNumber: string, cachedLeads: number): Promise<number> {
  const apiKey = process.env.PF_API_KEY;
  if (!apiKey) return cachedLeads;

  try {
    const response = await fetch(`https://api.propertyfinder.eg/crm/leads?reference=${referenceNumber}`, {
      headers: { 'Authorization': `Bearer ${apiKey}` }
    });

    if (!response.ok) {
      console.warn(`[Advisory AI] CRM fetch failed for ${referenceNumber}. Status: ${response.status}`);
      return cachedLeads;
    }

    const data: LeadData = await response.json();
    return data.total_leads || 0;
  } catch (err) {
    console.warn(`[Advisory AI] CRM network error for ${referenceNumber}. Using cached.`);
    return cachedLeads;
  }
}

/**
 * Advisory AI Decision Logic
 * Rules:
 * - High Value Protection: Price >= 50,000,000 EGP are never unpublished
 * - Low Performance: Leads < 2 are unpublished (if not protected)
 */
function evaluateProperty(price: number, leads: number): EvaluationResult {
  const isHighValue = price >= 50000000;
  const lowPerformance = leads < 2;

  if (lowPerformance && !isHighValue) {
    return {
      shouldUnpublish: true,
      reason: "Low performance (< 2 leads)",
      isHighValue,
      leadsFound: leads
    };
  }

  return {
    shouldUnpublish: false,
    reason: isHighValue ? "High Value Protected (>= 50M)" : "Healthy Performance",
    isHighValue,
    leadsFound: leads
  };
}

/**
 * Main Protocol Logic separated from HTTP handler
 */
async function processLeadTracking() {
  const allProperties = await getProperties();

  // Primary Sort: Price (Desc), Secondary Sort: Leads (Desc)
  const activeProperties = allProperties
    .filter(p => p.isPublished !== false)
    .sort((a, b) => {
      if (b.price !== a.price) return b.price - a.price;
      return (b.leadsCount || 0) - (a.leadsCount || 0);
    });

  const actions: string[] = [];
  const report: any[] = [];
  let unpublishedCount = 0;

  for (const property of activeProperties) {
    if (!property.id) continue;

    // 1. Fetch real-time data
    const leadsCount = await fetchCRMLeads(property.referenceNumber, property.leadsCount || 0);

    // 2. Evaluate
    const decision = evaluateProperty(property.price, leadsCount);

    // 3. Act
    if (decision.shouldUnpublish) {
      await unpublishProperty(property.id, decision.leadsFound);
      unpublishedCount++;
      actions.push(`Unpublished [${property.referenceNumber}] - Leads: ${decision.leadsFound} (${decision.reason})`);
    } else {
      actions.push(`Retained [${property.referenceNumber}] - Leads: ${decision.leadsFound} (${decision.reason})`);
    }

    // 4. Record
    report.push({
      ref: property.referenceNumber,
      price: property.price,
      leads: decision.leadsFound,
      status: decision.shouldUnpublish ? "Unpublished" : "Published",
      isHighValue: decision.isHighValue
    });
  }

  return { activeProperties, unpublishedCount, actions, report };
}

// --- Main HTTP Handler ---

export async function GET(request: Request) {
  try {
    // 1. Authenticate Cron Request
    const authHeader = request.headers.get("authorization");
    const cronSecret = process.env.CRON_SECRET;

    if (cronSecret && authHeader !== `Bearer ${cronSecret}`) {
      return new NextResponse("Unauthorized", { status: 401 });
    }

    console.log("[Advisory AI] Starting Lead Analysis Protocol...");

    // 2. Run the process
    const { activeProperties, unpublishedCount, actions, report } = await processLeadTracking();

    console.log(`[Advisory AI] Protocol Complete. Analyzed ${activeProperties.length}, Unpublished: ${unpublishedCount}`);

    return NextResponse.json({
      status: "success",
      message: `Analyzed ${activeProperties.length} properties. Unpublished ${unpublishedCount}.`,
      ranked_report: report,
      actions: actions,
    }, { status: 200 });

  } catch (error) {
    console.error("[Advisory AI] Critical Error in Lead Tracking Protocol:", error);
    return NextResponse.json({ 
      error: "Internal Server Error",
      details: error instanceof Error ? error.message : "Unknown error"
    }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { getProperties, getAgents } from "@/lib/firestore";
import { CONTACT } from "@/lib/site";
import { resolveProperties } from "@/lib/properties";

// --- Types ---
interface Agent {
  id: string;
  name: string;
  email: string;
  phone: string;
}

interface Property {
  id: string;
  referenceNumber: string;
  updatedAt: string;
  title: string;
  description: string;
  propertyType: string;
  offerType: string;
  price: number;
  city: string;
  community: string;
  subCommunity?: string;
  bedrooms: number;
  bathrooms: number;
  size: number;
  agentRef?: string;
  facilities?: string[];
  images?: string[];
  leadsCount?: number;
  isPublished?: boolean;
}

// --- Helper Functions ---

/**
 * Filter, Sort (Price then Leads), and Slice (Top 100)
 */
function prioritizeProperties(rawProperties: any[]): Property[] {
  return resolveProperties(rawProperties.filter(p => p.isPublished !== false))
    .sort((a, b) => {
      // Primary sort: Price (Highest first)
      if (b.price !== a.price) return b.price - a.price;
      // Secondary sort: Lead Count (Most first)
      return (b.leadsCount || 0) - (a.leadsCount || 0);
    })
    .slice(0, 100);
}

/**
 * Create a map of agents for quick lookup
 */
function createAgentMap(agents: any[]): Record<string, Agent> {
  return agents.reduce((acc, agent) => {
    if (agent.id) {
      acc[agent.id] = {
        id: agent.id,
        name: agent.name,
        email: agent.email,
        phone: agent.phone,
      };
    }
    return acc;
  }, {} as Record<string, Agent>);
}

/**
 * Maps a single property to XML fragment
 */
function mapPropertyToXml(prop: Property, agentMap: Record<string, Agent>): string {
  const agent = (prop.agentRef ? agentMap[prop.agentRef] : undefined) || {
    name: "Sierra Blu Advisory",
    email: CONTACT.email,
    phone: CONTACT.phoneDisplay,
  };

  let xml = `  <property last_update="${prop.updatedAt}">\n`;
  xml += `    <reference_number>${prop.referenceNumber}</reference_number>\n`;
  xml += `    <permit_number>123456789</permit_number>\n`;
  xml += `    <url>https://sierra-blu.com/listings/${encodeURIComponent(prop.referenceNumber)}</url>\n`;
  xml += `    <title><![CDATA[${prop.title}]]></title>\n`;
  xml += `    <description><![CDATA[${prop.description}]]></description>\n`;
  xml += `    <property_type>${prop.propertyType}</property_type>\n`;
  xml += `    <offer_type>${prop.offerType}</offer_type>\n`;
  xml += `    <price>${prop.price}</price>\n`;
  xml += `    <city><![CDATA[${prop.city}]]></city>\n`;
  xml += `    <community><![CDATA[${prop.community}]]></community>\n`;
  if (prop.subCommunity) {
    xml += `    <sub_community><![CDATA[${prop.subCommunity}]]></sub_community>\n`;
  }
  xml += `    <bedrooms>${prop.bedrooms}</bedrooms>\n`;
  xml += `    <bathrooms>${prop.bathrooms}</bathrooms>\n`;
  xml += `    <size>${prop.size}</size>\n`;

  // Agent Details
  xml += `    <agent>\n`;
  xml += `      <id>${prop.agentRef || 'admin'}</id>\n`;
  xml += `      <name><![CDATA[${agent.name}]]></name>\n`;
  xml += `      <email><![CDATA[${agent.email}]]></email>\n`;
  xml += `      <phone><![CDATA[${agent.phone}]]></phone>\n`;
  xml += `    </agent>\n`;

  // Facilities
  if (prop.facilities && prop.facilities.length > 0) {
    xml += `    <facilities>\n`;
    prop.facilities.forEach((fac) => {
      xml += `      <facility><![CDATA[${fac}]]></facility>\n`;
    });
    xml += `    </facilities>\n`;
  }

  // Photos
  if (prop.images && prop.images.length > 0) {
    xml += `    <photo>\n`;
    prop.images.forEach((img) => {
      xml += `      <url><![CDATA[${img}]]></url>\n`;
    });
    xml += `    </photo>\n`;
  }

  xml += `  </property>\n`;
  return xml;
}

// --- Main HTTP Handler ---

export async function GET() {
  try {
    const rawProperties = await getProperties();
    const rankedProperties = prioritizeProperties(rawProperties);

    const agents = await getAgents();
    const agentMap = createAgentMap(agents);

    let xml = `<?xml version="1.0" encoding="UTF-8"?>\n`;
    xml += `<list last_update="${new Date().toISOString()}">\n`;

    // Process each ranked property
    rankedProperties.forEach((prop) => {
      xml += mapPropertyToXml(prop, agentMap);
    });

    xml += `</list>`;

    return new NextResponse(xml, {
      status: 200,
      headers: {
        "Content-Type": "application/xml; charset=utf-8",
        "Cache-Control": "s-maxage=3600, stale-while-revalidate",
        "X-Listing-Count": rankedProperties.length.toString()
      },
    });
  } catch (error) {
    console.error("[Property Finder Feed] Fatal Error:", error);
    return NextResponse.json({ 
      error: "Failed to generate XML feed",
      details: error instanceof Error ? error.message : "Unknown error" 
    }, { status: 500 });
  }
}

