          {/* ── Logo ── */}
          <Link href="/" className="flex items-center gap-3 group">
            <div className={`w-9 h-9 rounded-full border-2 flex items-center justify-center transition-all duration-300 ${
              isScrolled
                ? "border-[var(--navy-900)] bg-[var(--navy-900)]"
                : "border-white bg-white/10 backdrop-blur-md"
            }`}>
              <span className={`text-xs font-bold tracking-tighter ${isScrolled ? "text-white" : "text-white"}`}>SB</span>
            </div>
            <div className="flex flex-col leading-none">
              <span className={`text-base font-semibold tracking-tight transition-colors duration-300 ${
                isScrolled ? "text-[var(--navy-900)]" : "text-white"
              }`}>
                Sierra Blu
              </span>
              <span className={`text-[8px] uppercase tracking-[0.3em] font-bold transition-colors duration-300 ${
                isScrolled ? "text-[var(--gold-500)]" : "text-white/60"
              }`}>
                Real Estate
              </span>
            </div>
          </Link>

          {/* ── Desktop Nav ── */}
          <div className="hidden md:flex items-center gap-8">
            {NAV_LINKS.map((link) => {
              const isActive = pathname === link.href;
              return (
                <Link
                  key={link.href}
                  href={link.href}
                  className={`relative text-[11px] font-semibold uppercase tracking-widest transition-colors duration-300 py-1 ${
                    isScrolled
                      ? isActive
                        ? "text-[var(--navy-900)]"
                        : "text-[var(--blue-gray)] hover:text-[var(--navy-900)]"
                      : isActive
                        ? "text-white"
                        : "text-white/70 hover:text-white"
                  }`}
                >
                  {link.label}
                  {isActive && (
                    <span className="absolute -bottom-0.5 left-0 right-0 h-[1.5px] bg-[var(--gold-500)] rounded-full" />
                  )}
                </Link>
              );
            })}
          </div>

          {/* ── Actions ── */}
          <div className="flex items-center gap-4">
            {/* Language switcher */}
            <div className={`hidden lg:flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest transition-colors duration-300 ${
              isScrolled ? "text-[var(--blue-gray)]" : "text-white/50"
            }`}>
              <span className={isScrolled ? "text-[var(--navy-900)] border-b border-[var(--gold-500)]" : "text-white border-b border-white/40"}>EN</span>
              <span>/</span>
              <span className="hover:text-[var(--gold-500)] cursor-pointer transition-colors">AR</span>
            </div>

            <UserNav />

            <Link
              href="/portal"
              className={`hidden lg:inline-flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest px-5 py-2.5 rounded-full border transition-all duration-300 ${
                isScrolled
                  ? "border-[var(--navy-900)] text-[var(--navy-900)] hover:bg-[var(--navy-900)] hover:text-white"
                  : "border-white/40 text-white hover:border-white hover:bg-white/10"
              }`}
            >
              Portal
            </Link>

            {/* Mobile toggle */}
            <button
              className={`md:hidden w-9 h-9 rounded-full border flex items-center justify-center transition-all duration-300 ${
                isScrolled
                  ? "border-[var(--mist)] text-[var(--navy-900)]"
                  : "border-white/20 text-white"
              }`}
              onClick={() => setMobileOpen(!mobileOpen)}
              aria-label="Toggle menu"
            >
              {mobileOpen ? <X className="w-4 h-4" /> : <Menu className="w-4 h-4" />}
            </button>
          </div>
        </div>
      </nav>

      {/* ── Mobile Menu ── */}
      <AnimatePresence>
        {mobileOpen && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[60] md:hidden"
          >
            <div
              className="absolute inset-0 bg-[var(--navy-900)]/60 backdrop-blur-sm"
              onClick={() => setMobileOpen(false)}
            />
            <motion.div
              initial={{ x: "100%" }}
              animate={{ x: 0 }}
              exit={{ x: "100%" }}
              transition={{ type: "spring", damping: 30, stiffness: 300 }}
              className="absolute top-0 right-0 h-full w-80 bg-white shadow-2xl flex flex-col pt-24 px-8"
            >
              <div className="space-y-1">
                {NAV_LINKS.map((link, i) => (
                  <motion.div
                    key={link.href}
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: i * 0.06 + 0.1 }}
                  >
                    <Link
                      href={link.href}
                      className="flex items-center justify-between py-3.5 border-b border-[var(--mist)] text-[var(--navy-900)] font-medium text-sm hover:text-[var(--gold-500)] transition-colors"
                      onClick={() => setMobileOpen(false)}
                    >
                      {link.label}
                      <ChevronDown className="w-3.5 h-3.5 -rotate-90 text-[var(--silver)]" />
                    </Link>
                  </motion.div>
                ))}
              </div>

              <div className="mt-auto pb-10">
                <Link
                  href="/portal"
                  className="btn-primary w-full text-center justify-center"
                  onClick={() => setMobileOpen(false)}
                >
                  Access Portal
                </Link>
                <p className="mt-6 text-[10px] uppercase tracking-[0.25em] text-[var(--silver)] text-center">
                  Sierra Blu · Fifth Settlement
                </p>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}
